function unicode_random () {
  let result = "", i = 0
  for (; i < 255; i++) {
    result += String.fromCharCode((Math.floor(1 + Math.random()* 6435)).toString(16))
  }
  console.log(result)
}

function unicode_range (start, end) { 
  let result = "", i = start
  for (; i < end; i++) {
    result += String.fromCharCode(i)
  }
  console.log(result)
}

function unicode_range_cp (start, end) { // (0x10080,0x100FF) LINEAR B PICTOGRAMS
  let result = "", i = start
  for (; i < end; i++) {
    result += String.fromCodePoint(i)
  }
  console.log(result)
}

