function drawAscii (lines) {
  swapWithOff()
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let i = 0, x = 0, y = 0, fs = canvas.width * 0.012
  ctx.font = "800 "+(fs)+"pt Courier"
  let w = lines[0].length * fs//ctx.measureText(lines[0]).width
  let scale = canvas.width/w
  fs *= scale * 0.9
  y += fs*1.5+4
  let x0 = x
  let c = 0, chars = []
  ctx.font = "800 "+(fs)+"pt Courier"
  ctx.fillStyle = getselectedcolor()
  for (; i < lines.length; i++) {
    c = 0, x = x0
    chars = lines[i].split("")
    for (; c < chars.length; c++) {
      ctx.fillText(chars[c], x, y)
      x += fs
    }
    y += fs * 1.5
  }
}

function brightnessOfRect (ctx,x,y,w, h) {
  if (!h)
    h = w
  let imgData = ctx.getImageData(x,y,w,h)
  let pixels = imgData.data;
  let i = 0, brightness = 0
  for (; i < pixels.length; i += 4) {
    brightness += (pixels[i]/255+pixels[i+1]/255+pixels[i+2]/255)
  }
  return brightness/(0.75*pixels.length)
}

