function drosteAt (x,y,W,color, a) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  let cs = W/24

  let p = [], cp = [], lastp = []
  let cx = x+W/2, cy = y+H/2, d = 0, angle = a
  handtest2At(x,y,W,color,20)             // 1
  handtest2At(x+cs*7.5,y+cs*4,W/2,color,40) // 2
  handtest2At(x+cs*11.7,y+cs*6.2,W/4,color,60) // 3
  handtest2At(x+cs*14.0,y+cs*7.7,W/8.8,color,80) // 4
  handtest2At(x+cs*15.0,y+cs*8.5,W/19,color,100) // 5
  handtest2At(x+cs*15.46,y+cs*8.93,W/44,color,120) // 6
  ctx.lineWidth = cs / 3

  //1
   ctx.beginPath()
  p = rotatePoint(x+2*cs+pet(d), y+26*cs+pet(d) ,cx,cy,angle)
  ctx.moveTo(p[0],p[1])
  p = rotatePoint(x+2*cs+pet(d), y-3*cs+pet(d) ,cx,cy,angle)
  ctx.lineTo(p[0],p[1])
  p = rotatePoint(x+22*cs+pet(d), y-3*cs+pet(d) ,cx,cy,angle)
  ctx.lineTo(p[0],p[1])
  p = rotatePoint(x+22*cs+pet(d), y+26*cs+pet(d) ,cx,cy,angle)
  ctx.lineTo(p[0],p[1])
  p = rotatePoint(x+2*cs+pet(d), y+26*cs+pet(d) ,cx,cy,angle)
  ctx.lineTo(p[0],p[1])
  ctx.stroke()

  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

