function cell_theoryAt (x,y,W,color) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = false
  let cs = W/24, d = 0, i = 0, maxi = 1
  ctx.lineWidth = W*0.01//1 + document.getElementById("featuresize").value/50
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "miter"
  for (; i < maxi; i++) { // WAVEY
    // bed
    //1
    ctx.beginPath()
    ctx.moveTo(x+5*cs+pet(d/2), y+13.5*cs+pet(d/2))
    ctx.lineTo(x+10*cs+pet(d), y+10.5*cs+pet(d))
    ctx.lineTo(x+24*cs+pet(d), y+16.5*cs+pet(d))
    ctx.lineTo(x+19*cs+pet(d), y+19.5*cs+pet(d))
    ctx.lineTo(x+5*cs+pet(d/2), y+13.5*cs+pet(d/2))
    ctx.stroke()

    //2
    ctx.beginPath()
    ctx.moveTo(x+5.5*cs+pet(d/2), y+13.7*cs+pet(d/2))
    ctx.lineTo(x+5.5*cs+pet(d/2), y+15.2*cs+pet(d/2))
    ctx.stroke()

    //3
    ctx.beginPath()
    ctx.moveTo(x+18.5*cs+pet(d/2), y+19.5*cs+pet(d/2))
    ctx.lineTo(x+18.5*cs+pet(d/2), y+20.7*cs+pet(d/2))
    ctx.stroke()

    //4
    ctx.beginPath()
    ctx.moveTo(x+23.5*cs+pet(d/2), y+17*cs+pet(d/2))
    ctx.lineTo(x+23.5*cs+pet(d/2), y+18*cs+pet(d/2))
    ctx.stroke()

    //1
    ctx.beginPath()
    ctx.moveTo(x+10*cs+pet(d/2), y-1*cs+pet(d/2))
    ctx.lineTo(x+24*cs+pet(d), y+5*cs+pet(d))
    ctx.lineTo(x+14*cs+pet(d), y+11*cs+pet(d))
    ctx.lineTo(x+0*cs+pet(d), y+5*cs+pet(d))
    ctx.lineTo(x+10*cs+pet(d/2), y+-1*cs+pet(d/2))
    ctx.stroke()

    //2
    ctx.beginPath()
    ctx.moveTo(x+14*cs+pet(d/2), y+12*cs+pet(d/2))
    ctx.lineTo(x+14*cs+pet(d), y+24*cs+pet(d))
    ctx.lineTo(x+24*cs+pet(d/2), y+18*cs+pet(d/2))
    ctx.stroke()

    //3
    ctx.beginPath()
    ctx.moveTo(x+14*cs+pet(d/2), y+24*cs+pet(d/2))
    ctx.lineTo(x+0*cs+pet(d), y+18*cs+pet(d))
    ctx.lineTo(x+0*cs+pet(d/2), y+5*cs+pet(d/2))
    ctx.stroke()

    //4
    ctx.beginPath()
    ctx.moveTo(x+24*cs+pet(d/2), y+5*cs+pet(d/2))
    ctx.lineTo(x+24*cs+pet(d/2), y+18*cs+pet(d/2))
    ctx.stroke()

    //5
    ctx.beginPath()
    ctx.moveTo(x+10*cs+pet(d/2), y+0*cs+pet(d/2))
    ctx.lineTo(x+10*cs+pet(d/2), y+12*cs+pet(d/2))
    ctx.stroke()

   //6
    ctx.beginPath()
    ctx.moveTo(x+0*cs+pet(d/2), y+18*cs+pet(d/2))
    ctx.lineTo(x+6.5*cs+pet(d/2), y+14.25*cs+pet(d/2))
    ctx.stroke()

    //pillow
    ctx.beginPath()
    ctx.moveTo(x+6.2*cs+pet(d/2), y+13.5*cs+pet(d/2))
    ctx.lineTo(x+9.6*cs+pet(d), y+15*cs+pet(d))
    ctx.lineTo(x+13.5*cs+pet(d), y+12.5*cs+pet(d))
    ctx.lineTo(x+10.1*cs+pet(d), y+11*cs+pet(d))
    ctx.lineTo(x+6.2*cs+pet(d/2), y+13.5*cs+pet(d/2))
    ctx.stroke()
    
  } //WAVEY
  ctx.save()
  ctx.beginPath()
  ctx.moveTo(x+14*cs+pet(d/2), y+24*cs+pet(d/2))
  ctx.lineTo(x+24*cs+pet(d), y+18*cs+pet(d))
  ctx.lineTo(x+24*cs+pet(d), y+5*cs+pet(d))
  ctx.lineTo(x+10*cs+pet(d), y+-1*cs+pet(d))
  ctx.lineTo(x+0*cs+pet(d), y+5*cs+pet(d))
  ctx.lineTo(x+0*cs+pet(d), y+18*cs+pet(d))
  ctx.lineTo(x+14*cs+pet(d/2), y+24*cs+pet(d/2))
  ctx.closePath()
  ctx.clip()
   ctx.lineWidth = W*0.014
  let j = 0
  for (; j < 1; j++) {
    i = 0
    //x = cs
    for (; i < 27; i++) {
      ctx.beginPath()
      ctx.moveTo(x + i*cs, y-cs*1)
      ctx.lineTo(x + i*cs, y+H)
      ctx.stroke()
    }
  }
  ctx.restore()
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

