function puffed_upAt (x,y,W,color) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = true
  let cs = W/24, d = 0, i = 0, maxi = 1, r = cs
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  if (WAVEY) {
    d = cs/2, maxi = 4
    ctx.lineWidth = 1 + document.getElementById("featuresize").value/150
  }
  ctx.strokeStyle = color
  ctx.fillStyle = savedF
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  pufferAt(x + cs*1, y-cs , cs*26, color)
  ctx.fillStyle = savedF
  for (; i < maxi; i++) { // WAVEY
    //1
    ctx.beginPath()
    ctx.moveTo(x+4*cs+pet(d/2), y+6*cs+pet(d/2))
    cpx = x+0*cs
    cpy = y+4*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+0*cs+pet(d), y+6*cs+pet(d))
    cpx = x+0*cs
    cpy = y+10*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+4*cs+pet(d), y+7*cs+pet(d))
    cpx = x+4*cs
    cpy = y+13*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+4*cs+pet(d), y+13*cs+pet(d))
    cpx = x+4*cs
    cpy = y+20*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+12*cs+pet(d), y+20*cs+pet(d))
    cpx = x+23*cs
    cpy = y+20*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+23*cs+pet(d), y+12*cs+pet(d))
    cpx = x+23*cs
    cpy = y+8*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+23*cs+pet(d), y+8*cs+pet(d))
    cpx = x+24*cs
    cpy = y+8*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+24*cs+pet(d), y+7*cs+pet(d))
    cpx = x+24*cs
    cpy = y+6*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+23*cs+pet(d), y+6*cs+pet(d))
    cpx = x+22*cs
    cpy = y+2*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+14*cs+pet(d), y+2*cs+pet(d))
    cpx = x+5*cs
    cpy = y+2*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+4*cs+pet(d/2), y+6*cs+pet(d/2))
    ctx.stroke()
    
    ctx.beginPath()
    ctx.moveTo(x+17*cs+pet(d/2), y+9*cs+pet(d/2))
    cpx = x+15*cs
    cpy = y+8*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+15*cs+pet(d), y+8*cs+pet(d))
    cpx = x+13*cs
    cpy = y+7*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+13*cs+pet(d), y+10*cs+pet(d))
    cpx = x+13*cs
    cpy = y+13*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+15*cs+pet(d), y+12*cs+pet(d))
    cpx = x+17*cs
    cpy = y+10*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+17*cs+pet(d/2), y+10*cs+pet(d/2))
    if (i === 0)
      ctx.fill()
    ctx.stroke()

    //2
    ctx.beginPath()
    ctx.arc(x+20*cs+pet(d/2), y+6*cs+pet(d/2), r, 0, 2*Math.PI)
    if (i === 0) {
      ctx.fill()
    }
    ctx.stroke()
    if (i === 0) {
      ctx.fillStyle = color
      ctx.beginPath()
      ctx.arc(x+20*cs+pet(d/2), y+6*cs+pet(d/2), r/2, 0, 2*Math.PI)
      ctx.fill()
    }
    // mouth
    ctx.beginPath()
    ctx.moveTo(x+23.25*cs+pet(d/2), y+7*cs+pet(d/2))
    ctx.lineTo(x+24*cs+pet(d/2), y+7*cs+pet(d/2))
    ctx.stroke()
    //3
    ctx.beginPath()
    ctx.moveTo(x+10*cs+pet(d/2), y+20*cs+pet(d/2))
    cpx = x+10*cs
    cpy = y+22*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+9*cs+pet(d), y+22*cs+pet(d))
    cpx = x+7*cs
    cpy = y+22*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+7*cs+pet(d), y+21*cs+pet(d))
    cpx = x+7*cs
    cpy = y+20*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+10*cs+pet(d/2), y+20*cs+pet(d/2))
    ctx.stroke()

    //4
    ctx.beginPath()
    ctx.moveTo(x+10*cs+pet(d/2), y+2*cs+pet(d/2))
    cpx = x+10*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+9*cs+pet(d), y+0*cs+pet(d))
    cpx = x+7*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+7*cs+pet(d), y+1*cs+pet(d))
    cpx = x+7*cs
    cpy = y+2*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+10*cs+pet(d/2), y+2*cs+pet(d/2))
    ctx.stroke()
  } //WAVEY
  
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

function pufferAt (x,y,W,color) { 
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let colors = shuffle(getCurrentPalette(true,13))
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  let i = 0, j = 0, x0 = x, y0 = y
  let r = W/2.9, d = 0
  let a = 0.3
  let x2 = 0, y2 = 0
  for (; j < 1; j++) {
    i = 0
    r = W/2.9, d = W/120
    a = 0.3
    x2 = 0
    y2 = 0
    x -= 2*W/24, y -= 2*H/24
    let cx = W/2, cy = H/2
    for (; i < 17; i++) {
      x2 = r * Math.cos(a)+cx
      y2 = r * Math.sin(a)+cy
      spineAt (x+x2+pet(d), y+y2,W/9+pet(d), color,a*180/Math.PI + Math.PI/2*180/Math.PI)
      a += Math.PI/8.5
    }
    a += 0.13
    i = 0, r *= 0.7
    for (; i < 13; i++) {
      x2 = r * Math.cos(a)+cx
      y2 = r * Math.sin(a)+cy
      spineAt (x+x2+pet(d), y+y2+pet(d), W/9,color,a*180/Math.PI + Math.PI/2*180/Math.PI)
      a += Math.PI/6.5
    }
    a += 0.13
    i = 0, r *= 0.6
    for (; i < 11; i++) {
      x2 = r * Math.cos(a)+cx
      y2 = r * Math.sin(a)+cy
      spineAt (x+x2+pet(d), y+y2+pet(d), W/9,color,a*180/Math.PI + Math.PI/2*180/Math.PI)
      a += Math.PI/5.5
    }
    a += 0.13
    i = 0, r *= 0.35
    for (; i < 4; i++) {
      x2 = r * Math.cos(a)+cx
      y2 = r * Math.sin(a)+cy
      spineAt (x+x2+pet(d), y+y2+pet(d), W/9,color,a*180/Math.PI  + Math.PI/2*180/Math.PI)
      a += Math.PI/2
    }
    x = x0, y = y0
  }
}

function spineAt (x,y,W,color, a) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "miter"
  let cs = W/24
  let p = [], cp = [], lastp = []
  let cx = x+W/2, cy = y+H/2, d = W/96, angle = a

  //1
  ctx.beginPath()
  p = rotatePoint(x+8*cs+pet(d), y+14*cs+pet(d) ,cx,cy,angle)
  ctx.moveTo(p[0],p[1])
  p = rotatePoint(x+12*cs+pet(d), y+0*cs+pet(d) ,cx,cy,angle)
  ctx.lineTo(p[0],p[1])
  p = rotatePoint(x+16*cs+pet(d), y+14*cs+pet(d) ,cx,cy,angle)
  ctx.lineTo(p[0],p[1])
  ctx.stroke()

  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

