  ctx.fillStyle = "#191919aa"
  let fs = W*0.04
  ctx.font = "italic "+fs+"pt Garamond"
  ctx.letterSpacing = (W*0.03)+"px";
  let w = ctx.measureText("Figure").width
  ctx.fillText("Figure", x+W/2-w/2, y+25.5*cs)
  ctx.letterSpacing = "0px";
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
