function ballroom2At (x,y,W,color) { // roach motel
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = false
  let cs = W/24, d = 0, i = 0, maxi = 32
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  //y -= 2*cs
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  ctx.save()
    //1
  ctx.beginPath()
  ctx.moveTo(x+11*cs+pet(d/2), y+21*cs+pet(d/2))
  ctx.lineTo(x+0*cs+pet(d), y+11*cs+pet(d))
  ctx.lineTo(x+0*cs+pet(d), y+3*cs+pet(d))
  ctx.lineTo(x+13*cs+pet(d), y+3*cs+pet(d))
  ctx.lineTo(x+24*cs+pet(d), y+12*cs+pet(d))
  ctx.lineTo(x+11*cs+pet(d), y+12*cs+pet(d))
  ctx.lineTo(x+11*cs+pet(d/2), y+21*cs+pet(d/2))
  ctx.fillStyle = '#3f2a0d'
  ctx.fill()
  ctx.clip()
  let x0 = x, y0 = y
  let colors = ["#543d1f","#805a01","#3e2104","#222222"]
  d = cs*1.5
  ctx.globalAlpha = 0.5
  for (; i < maxi; i++) { // WAVEY
    ctx.beginPath()
    ctx.moveTo(x+11*cs, y+21*cs)
    cpx = x+11*cs
    cpy = y+17*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+11*cs, y+12*cs)
    cpx = x+17*cs
    cpy = y+12*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+24*cs, y+12*cs)
    ctx.strokeStyle = randomPick(colors)
    ctx.lineWidth = randomPick([4,2,3,5,6,8,2])
    ctx.stroke()
    x -= cs/2
    y -= cs/2.6
  } 
  x = x0, y = y0, d = 0
  ctx.restore()
  ctx.beginPath()
  ctx.moveTo(x+11*cs+pet(d/2), y+12*cs+pet(d/2))
  ctx.lineTo(x+11*cs+pet(d), y+16*cs+pet(d))
  ctx.lineTo(x+20*cs+pet(d), y+16*cs+pet(d))
  ctx.lineTo(x+20*cs+pet(d), y+12*cs+pet(d))
  ctx.lineTo(x+11*cs+pet(d/2), y+12*cs+pet(d/2))
  ctx.fillStyle = "#111111"
  ctx.fill()
  ctx.globalAlpha = 1

  ctx.save()
  ctx.beginPath()
  ctx.moveTo(x+11*cs+pet(d/2), y+16*cs+pet(d/2))
  ctx.lineTo(x+11*cs+pet(d), y+21*cs+pet(d))
  ctx.lineTo(x+24*cs+pet(d), y+21*cs+pet(d))
  ctx.lineTo(x+20*cs+pet(d), y+16*cs+pet(d))
  ctx.lineTo(x+11*cs+pet(d/2), y+16*cs+pet(d/2))
  ctx.clip()
  ctx.fillStyle = '#3f2a0d'
  ctx.fill()

  //5
  i = 0, d = cs
  ctx.globalAlpha = 0.5
  for (; i < 13; i++) {
    ctx.strokeStyle = randomPick(colors)
    ctx.lineWidth = randomPick([4,2,3,5,6,8,2])
    ctx.beginPath()
    ctx.moveTo(x+10*cs+pet(d/2), y+14*cs+pet(d/2))
    ctx.lineTo(x+24*cs+pet(d/2), y+14*cs+pet(d/2))
    ctx.stroke()
    y += cs/2
  }
  ctx.globalAlpha = 1
  ctx.restore()
  d = 0, x = x0, y = y0
  ctx.save()
  ctx.beginPath()
  ctx.moveTo(x+20*cs+pet(d/2), y+12*cs+pet(d/2))
  ctx.lineTo(x+20*cs+pet(d), y+16*cs+pet(d))
  ctx.lineTo(x+24*cs+pet(d), y+21*cs+pet(d))
  ctx.lineTo(x+24*cs+pet(d), y+12*cs+pet(d))
  ctx.lineTo(x+20*cs+pet(d/2), y+12*cs+pet(d/2))
  ctx.fillStyle = '#3f2a0d'
  ctx.fill()
  ctx.clip()
  i = 0, d = cs
  ctx.globalAlpha = 0.5
  for (; i < 13; i++) {
    ctx.strokeStyle = randomPick(colors)
    ctx.lineWidth = randomPick([4,2,3,5,6,8,2])
    ctx.beginPath()
    ctx.moveTo(x+20*cs+pet(d/2), y+10*cs+pet(d/2))
    ctx.lineTo(x+20*cs+pet(d/2), y+22*cs+pet(d/2))
    ctx.stroke()
    x += cs/2
  }
  ctx.globalAlpha = 1
  ctx.restore()
  d = 0, x = x0, y = y0

  ctx.beginPath()
  ctx.moveTo(x+0*cs+pet(d/2), y+3*cs+pet(d/2))
  ctx.lineTo(x+11*cs+pet(d), y+12*cs+pet(d))
  ctx.lineTo(x+24*cs+pet(d), y+12*cs+pet(d))
  ctx.lineTo(x+13*cs+pet(d/2), y+3*cs+pet(d/2))
  ctx.fillStyle = "#ffffff20"
  ctx.fill()
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

