function ballroom1At (x,y,W,color) {
  color = "#f4c701"
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = true
  let cs = W/32, d = 0, i = 0, maxi = 1, x0 = x, y0 = y
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  if (WAVEY) {
    d = cs/1.2, maxi = 9
    ctx.lineWidth = 1 + document.getElementById("featuresize").value/30
  }
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  ctx.globalAlpha = 0.76

  ctx.beginPath()
  ctx.moveTo(x+18*cs+pet(d/2), y+4*cs+pet(d/2))
  ctx.lineTo(x+32*cs+pet(d), y+16*cs+pet(d))
  ctx.lineTo(x+32*cs+pet(d), y+28*cs+pet(d))
  ctx.lineTo(x+14*cs+pet(d), y+28*cs+pet(d))
  ctx.lineTo(x+0*cs+pet(d), y+15*cs+pet(d))
  ctx.lineTo(x+0*cs+pet(d), y+4*cs+pet(d))
  ctx.lineTo(x+18*cs+pet(d/2), y+4*cs+pet(d/2))
  ctx.fillStyle = 'gold'
  ctx.globalAlpha = 0.33
  ctx.fillStyle = color//adjustBrightnessC(color, (Math.random()-0.5) * 40)
  for (; i < maxi; i++) { // WAVEY
    //1
    color = "#f4c701"
    ctx.strokeStyle = adjustBrightnessC(color, (Math.random()>0.5)?40:-40 )
    ctx.beginPath()
    d *= 2
    ctx.moveTo(x+18*cs+pet(d/2), y+4*cs+pet(d/2))
    ctx.lineTo(x+32*cs+pet(d), y+16*cs+pet(d))
    ctx.lineTo(x+32*cs+pet(d), y+28*cs+pet(d))
    ctx.lineTo(x+14*cs+pet(d), y+28*cs+pet(d))
    ctx.lineTo(x+0*cs+pet(d), y+15*cs+pet(d))
    ctx.lineTo(x+0*cs+pet(d), y+4*cs+pet(d))
    ctx.lineTo(x+18*cs+pet(d/2), y+4*cs+pet(d/2))
    ctx.globalAlpha = 0.15
    d /= 2
    ctx.fill()

    ctx.beginPath()
    ctx.moveTo(x+18*cs+pet(d/2), y+4*cs+pet(d/2))
    ctx.lineTo(x+32*cs+pet(d), y+16*cs+pet(d))
    ctx.lineTo(x+32*cs+pet(d), y+28*cs+pet(d))
    ctx.lineTo(x+14*cs+pet(d), y+28*cs+pet(d))
    ctx.lineTo(x+0*cs+pet(d), y+15*cs+pet(d))
    ctx.lineTo(x+0*cs+pet(d), y+4*cs+pet(d))
    ctx.lineTo(x+18*cs+pet(d/2), y+4*cs+pet(d/2))
    ctx.globalAlpha = 0.33
    ctx.stroke()

    //2
    ctx.beginPath()
    ctx.moveTo(x+32*cs+pet(d/2), y+16*cs+pet(d/2))
    ctx.lineTo(x+14*cs+pet(d), y+16*cs+pet(d))
    ctx.lineTo(x+0*cs+pet(d/2), y+4*cs+pet(d/2))
    ctx.stroke()

    //3
    ctx.beginPath()
    ctx.moveTo(x+14*cs+pet(d/2), y+16*cs+pet(d/2))
    ctx.lineTo(x+14*cs+pet(d/2), y+28*cs+pet(d/2))
    ctx.stroke()

    //3
    ctx.beginPath()
    ctx.moveTo(x+14*cs+pet(d/2), y+18*cs+pet(d/2))
    ctx.lineTo(x+32*cs+pet(d), y+18*cs+pet(d))
    ctx.lineTo(x+32*cs+pet(d), y+17*cs+pet(d))
    ctx.lineTo(x+14*cs+pet(d), y+17*cs+pet(d))
    ctx.lineTo(x+14*cs+pet(d/2), y+18*cs+pet(d/2))
    ctx.stroke()

    ctx.beginPath()
    ctx.moveTo(x+1*cs+pet(d/2), y+6*cs+pet(d/2))
    ctx.lineTo(x+14*cs+pet(d), y+17*cs+pet(d))
    ctx.lineTo(x+14*cs+pet(d), y+18*cs+pet(d))
    ctx.lineTo(x+1*cs+pet(d/2), y+7*cs+pet(d/2))
    ctx.stroke()

    ctx.beginPath()
    ctx.moveTo(x+32*cs+pet(d/2), y+26*cs+pet(d/2))
    ctx.lineTo(x+14*cs+pet(d), y+26*cs+pet(d))
    ctx.lineTo(x+14*cs+pet(d), y+24*cs+pet(d))
    ctx.lineTo(x+1*cs+pet(d/2), y+12*cs+pet(d/2))
    ctx.stroke()

    ctx.beginPath()
    ctx.moveTo(x+14*cs+pet(d/2), y+16*cs+pet(d/2))
    ctx.lineTo(x+23*cs+pet(d), y+13*cs+pet(d))
    ctx.lineTo(x+32*cs+pet(d), y+16*cs+pet(d))
    ctx.lineTo(x+14*cs+pet(d/2), y+16*cs+pet(d/2))
    ctx.stroke()

    //3
    ctx.beginPath()
    ctx.moveTo(x+14*cs+pet(d/2), y+15.5*cs+pet(d/2))
    ctx.lineTo(x+22*cs+pet(d/2), y+12.75*cs+pet(d/2))
    ctx.stroke()
    let j = 0
    for (; j < 17; j++) { // WAVEY
      //1
      ctx.beginPath()
      ctx.moveTo(x+15*cs+pet(d/2), y+18*cs+pet(d/2))
      if (j % 2 === 0)
        ctx.lineTo(x+15*cs+pet(d/2), y+26*cs+pet(d/2))
      else
        ctx.lineTo(x+15*cs+pet(d/2), y+24*cs+pet(d/2))
      ctx.stroke()
      x += cs
    } 
    x = x0

    j = 0
    for (; j < 17; j++) { // WAVEY
      //1
      ctx.beginPath()
      ctx.moveTo(x+1*cs+pet(d/2), y+7*cs+pet(d/2))
      ctx.lineTo(x+1*cs+pet(d/2), y+11*cs+pet(d/2))
      ctx.stroke()
      x += cs
      y += cs*0.9
    } 
    x = x0, y = y0
  } //WAVEY
   ctx.globalAlpha = 1
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

