function shield_and_weaponAt (x,y,W,color) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = true
  let cs = W/24, d = 0, i = 0, maxi = 1
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  if (WAVEY) {
    d = cs/2, maxi = 13
    ctx.lineWidth = 1 + document.getElementById("featuresize").value/150
  }
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "butt"
  ctx.lineJoin = "bevel"
  let x0 = x, y0 = y, x2,y2
  let r = cs*13
  let angle = 1.4*Math.PI, inc = Math.PI/60
  let cx = x+10*cs+pet(d/2), cy = y+18*cs+pet(d/2)
  for (; i < 13; i++) {
    ctx.beginPath()
    ctx.moveTo(cx,cy)
    x2 = r * Math.cos(angle)+cx
    y2 = r * Math.sin(angle)+cy 
    ctx.lineTo(x2,y2)
    ctx.stroke()
    angle += inc
  }
  i = 0
  angle = 0.4*Math.PI, inc = Math.PI/60
  cx = x+14*cs+pet(d/2), cy = y+6*cs+pet(d/2)
  for (; i < 13; i++) {
    ctx.beginPath()
    ctx.moveTo(cx,cy)
    x2 = r * Math.cos(angle)+cx
    y2 = r * Math.sin(angle)+cy 
    ctx.lineTo(x2,y2)
    ctx.stroke()
    angle += inc
  }

  ctx.beginPath()
    ctx.moveTo(x+10*cs+pet(d/2), y+18*cs+pet(d/2))
    ctx.lineTo(x+14*cs+pet(d/2), y+6*cs+pet(d/2))
    ctx.stroke()
  i = 0
d /= 2
  for (; i < 10; i++) { // dots
    ctx.beginPath()
    ctx.arc(x+3*cs+pet(d/2), y+8.5*cs+pet(d/2), cs/4, 0, 2*Math.PI)
    ctx.fill()
    ctx.beginPath()
    ctx.arc(x+4*cs+pet(d), y+8.5*cs+pet(d), cs/4, 0, 2*Math.PI)
    ctx.fill()
    ctx.beginPath()
    ctx.arc(x+5*cs+pet(d/2), y+8.5*cs+pet(d/2), cs/4, 0, 2*Math.PI)
    ctx.fill()
    x += cs/2.35
    y += cs/1
  }
  d *= 2
  x = x0, y = y0

  i = 0
  for (; i < 14; i++) { //white keys
    ctx.beginPath()
    ctx.moveTo(x+15.3*cs+pet(d/2), y+6.2*cs+pet(d/2))
    ctx.lineTo(x+17.2*cs+pet(d/2), y+5*cs+pet(d/2))
    ctx.stroke()
    x += cs/2.9
    y += cs/1.25
  }
  x = x0, y = y0
  let skips = [3,6,10,13]
   i = 0
   ctx.lineWidth *= 4
  for (; i < 14; i++) { //black keys
    ctx.beginPath()
    ctx.moveTo(x+15.3*cs+pet(d/2), y+6.2*cs+pet(d/2))
    ctx.lineTo(x+16.2*cs+pet(d/2), y+5.6*cs+pet(d/2))
    if (!skips.includes(i))
     ctx.stroke()
    x += cs/2.9
    y += cs/1.25
  }
  ctx.lineWidth /= 4
  x = x0, y = y0

  i = 0
  for (; i < maxi; i++) { // WAVEY
    //11 handles
    ctx.beginPath()
    ctx.moveTo(x+5*cs+pet(d/2), y+16*cs+pet(d/2))
    cpx = x+4*cs
    cpy = y+17*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+3*cs+pet(d), y+15*cs+pet(d))
    cpx = x+2*cs
    cpy = y+13*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+3.3*cs+pet(d/2), y+12*cs+pet(d/2))
    ctx.stroke()

    //12
    y += cs
    ctx.beginPath()
    ctx.moveTo(x+19*cs+pet(d/2), y+7*cs+pet(d/2))
    cpx = x+20*cs
    cpy = y+6*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+21*cs+pet(d), y+8*cs+pet(d))
    cpx = x+22*cs
    cpy = y+10*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+20.5*cs+pet(d/2), y+11*cs+pet(d/2))
    ctx.stroke()
    y -= cs
    //10 white key base line
    ctx.beginPath()
    ctx.moveTo(x+15*cs+pet(d/2), y+5.5*cs+pet(d/2))
    ctx.lineTo(x+19.8*cs+pet(d/2), y+17.2*cs+pet(d/2))
    ctx.stroke()
    //1
    ctx.beginPath()
    ctx.moveTo(x+2*cs+pet(d/2), y+8*cs+pet(d/2))
    ctx.lineTo(x+5*cs+pet(d), y+6*cs+pet(d))
    ctx.lineTo(x+10*cs+pet(d), y+18*cs+pet(d))
    ctx.moveTo(x+14*cs+pet(d), y+6*cs+pet(d))
    ctx.lineTo(x+19*cs+pet(d), y+18*cs+pet(d))
    ctx.lineTo(x+22*cs+pet(d/2), y+16*cs+pet(d/2))
    ctx.stroke()
    //4
    ctx.beginPath()
    ctx.moveTo(x+5*cs+pet(d/2), y+6*cs+pet(d/2))
    ctx.lineTo(x+2*cs+pet(d), y+8*cs+pet(d))
    ctx.lineTo(x+7*cs+pet(d), y+20*cs+pet(d))
    ctx.lineTo(x+10*cs+pet(d/2), y+18*cs+pet(d/2))
    ctx.stroke()

    //5
    ctx.beginPath()
    ctx.moveTo(x+22*cs+pet(d/2), y+16*cs+pet(d/2))
    ctx.lineTo(x+17*cs+pet(d), y+4*cs+pet(d))
    ctx.lineTo(x+14*cs+pet(d/2), y+6*cs+pet(d/2))
    ctx.stroke()
 
    //13
    ctx.beginPath()
    ctx.moveTo(x+5*cs+pet(d/2), y+6*cs+pet(d/2))
    cpx = x+10*cs
    cpy = y+3*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+14*cs+pet(d/2), y+6*cs+pet(d/2))
    ctx.stroke()

    //14
    ctx.beginPath()
    ctx.moveTo(x+19*cs+pet(d/2), y+18*cs+pet(d/2))
    cpx = x+14*cs
    cpy = y+21*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+10*cs+pet(d/2), y+18*cs+pet(d/2))
    ctx.stroke()
  } //WAVEY


  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

function dedenkind_cutAt (x,y,W,color) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = true
  let cs = W/24, d = 0, i = 0, maxi = 1
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  if (WAVEY) {
    d = cs/2, maxi = 5
    ctx.lineWidth = 1 + document.getElementById("featuresize").value/150
  }
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  ctx.font = "800 italic "+(W*0.07)+"pt Garamond"
  let x_sqrt = 0
  ctx.line
  running_with_scissorsAt(x+5*cs+pet(d/2), y+0*cs+pet(d/2), W/2.4, color)
  for (; i < maxi; i++) { // WAVEY
    //1
    ctx.beginPath()
    ctx.moveTo(x+0*cs+pet(d/2), y+14*cs+pet(d/2))
    ctx.lineTo(x+24*cs+pet(d), y+14*cs+pet(d))
    ctx.lineTo(x+24*cs+pet(d), y+10*cs+pet(d))
    ctx.lineTo(x+0*cs+pet(d), y+10*cs+pet(d))
    ctx.lineTo(x+0*cs+pet(d/2), y+14*cs+pet(d/2))
    ctx.stroke()

    x_sqrt = x + W*Math.sqrt(2) - W

    //2
    ctx.beginPath()
    ctx.moveTo(x_sqrt+pet(d/2), y+10*cs+pet(d/2))
    ctx.lineTo(x_sqrt+pet(d/2), y+16*cs+pet(d/2))
    ctx.lineTo(x_sqrt+cs*2+pet(d/2), y+19*cs+pet(d/2))
    ctx.stroke()
    d = 0
    ctx.fillText("√2", x_sqrt+2.5*cs+pet(d/2), y+20.5*cs+pet(d/2))
    d = cs/2
    //4
    ctx.beginPath()
    ctx.moveTo(x+0*cs+pet(d/2), y+14*cs+pet(d/2))
    ctx.lineTo(x+1*cs+pet(d/2), y+16*cs+pet(d/2))
    ctx.stroke()
    d = 0
    ctx.fillText("1", x+1.5*cs+pet(d/2), y+17*cs+pet(d/2))
    d = cs/2
    //5
    ctx.beginPath()
    ctx.moveTo(x+24*cs+pet(d/2), y+10*cs+pet(d/2))
    ctx.lineTo(x+23*cs+pet(d/2), y+8*cs+pet(d/2))
    ctx.stroke()
    d = 0
    ctx.fillText("2", x+21.5*cs+pet(d/2), y+8*cs+pet(d/2))
    d = cs/2

  } //WAVEY
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

function food_pyramidAt (x,y,W,color) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = false
  let cs = W/24, d = 0, i = 0, maxi = 1
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  if (WAVEY) {
    d = cs/2, maxi = 13
    ctx.lineWidth = 1 + document.getElementById("featuresize").value/150
  }
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  for (; i < maxi; i++) { // WAVEY

    //2
    ctx.beginPath()
    ctx.moveTo(x+12*cs+pet(d/2), y+0*cs+pet(d/2))
    ctx.lineTo(x+0*cs+pet(d), y+20*cs+pet(d))
    ctx.lineTo(x+24*cs+pet(d), y+20*cs+pet(d))
    ctx.lineTo(x+12*cs+pet(d/2), y+0*cs+pet(d/2))
    ctx.stroke()

  } //WAVEY
  w = cs*3
  cakeAt(x+12*cs-w/2, y, w, color)

  cakeAt(x+12*cs-w, y+w, w, color)
  cakeAt(x+12*cs, y+w, w, color)
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

