  //3
  ctx.beginPath()
  ctx.moveTo(x+4*cs+pet(d/2), y+9*cs+pet(d/2))
  ctx.lineTo(x+9*cs+pet(d), y+4*cs+pet(d))
  ctx.lineTo(x+10*cs+pet(d/2), y+4*cs+pet(d/2))
  ctx.stroke()
  ctx.fillText(data[i++], x+10*cs+pet(d/2), y+4*cs+pet(d/2))

  //4
  ctx.beginPath()
  ctx.moveTo(x+8*cs+pet(d/2), y+9*cs+pet(d/2))
