function bird_rotAt (x,y,W,color, a) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  let cs = W/24
  let p = [], cp = [], lastp = []
  let cx = x+W/2, cy = y+H/2, d = 0, angle = a

  //1
  ctx.beginPath()
  p = rotatePoint(x+10*cs+pet(d), y+14*cs+pet(d) ,cx,cy,angle)
  ctx.moveTo(p[0],p[1])
  cpx = x+10*cs+pet(d)
  cpy = y+18*cs+pet(d)
  cp = rotatePoint(cpx,cpy,cx,cy,angle)
  p = rotatePoint(x+8*cs+pet(d), y+22*cs+pet(d),cx,cy,angle)
  ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
  cpx = x+12*cs+pet(d)
  cpy = y+24*cs+pet(d)
  cp = rotatePoint(cpx,cpy,cx,cy,angle)
  p = rotatePoint(x+16*cs+pet(d), y+22*cs+pet(d),cx,cy,angle)
  ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
  cpx = x+14*cs+pet(d)
  cpy = y+18*cs+pet(d)
  cp = rotatePoint(cpx,cpy,cx,cy,angle)
  p = rotatePoint(x+14*cs+pet(d), y+14*cs+pet(d),cx,cy,angle)
  ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
  cpx = x+19*cs+pet(d)
  cpy = y+18*cs+pet(d)
  cp = rotatePoint(cpx,cpy,cx,cy,angle)
  p = rotatePoint(x+24*cs+pet(d), y+18*cs+pet(d),cx,cy,angle)
  ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
  cpx = x+24*cs+pet(d)
  cpy = y+6*cs+pet(d)
  cp = rotatePoint(cpx,cpy,cx,cy,angle)
  p = rotatePoint(x+14*cs+pet(d), y+6*cs+pet(d),cx,cy,angle)
  ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
  cpx = x+14*cs+pet(d)
  cpy = y+2*cs+pet(d)
  cp = rotatePoint(cpx,cpy,cx,cy,angle)
  p = rotatePoint(x+16*cs+pet(d), y+2*cs+pet(d),cx,cy,angle)
  ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
  cpx = x+14*cs+pet(d)
  cpy = y+0*cs+pet(d)
  cp = rotatePoint(cpx,cpy,cx,cy,angle)
  p = rotatePoint(x+12*cs+pet(d), y+0*cs+pet(d),cx,cy,angle)
  ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
  cpx = x+10*cs+pet(d)
  cpy = y+0*cs+pet(d)
  cp = rotatePoint(cpx,cpy,cx,cy,angle)
  p = rotatePoint(x+10*cs+pet(d), y+6*cs+pet(d),cx,cy,angle)
  ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
  cpx = x+0*cs+pet(d)
  cpy = y+6*cs+pet(d)
  cp = rotatePoint(cpx,cpy,cx,cy,angle)
  p = rotatePoint(x+0*cs+pet(d), y+18*cs+pet(d),cx,cy,angle)
  ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
  cpx = x+5*cs+pet(d)
  cpy = y+18*cs+pet(d)
  cp = rotatePoint(cpx,cpy,cx,cy,angle)
  p = rotatePoint(x+10*cs+pet(d), y+14*cs+pet(d),cx,cy,angle)
  ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
  ctx.stroke()

  //2
  ctx.beginPath()
  p = rotatePoint(x+12.5*cs+pet(d), y+2*cs+pet(d) ,cx,cy,angle)
  ctx.arc(p[0],p[1], cs/2,0,2*Math.PI)
  ctx.stroke()

  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}
