  ctx.lineTo(x+20*cs+pet(d), y+5*cs+pet(d))
  ctx.lineTo(x+22*cs+pet(d), y+7*cs+pet(d))
  ctx.lineTo(x+28*cs+pet(d), y+4*cs+pet(d))
  ctx.lineTo(x+31*cs+pet(d), y+8*cs+pet(d))
  ctx.lineTo(x+32*cs+pet(d), y+8*cs+pet(d))
  ctx.lineTo(x+32*cs+pet(d), y+12*cs+pet(d))
  ctx.lineTo(x+26*cs+pet(d), y+15*cs+pet(d))
  ctx.lineTo(x+25*cs+pet(d), y+12*cs+pet(d))
  ctx.lineTo(x+21*cs+pet(d), y+11*cs+pet(d))
  ctx.lineTo(x+17*cs+pet(d), y+14*cs+pet(d))
  ctx.lineTo(x+14*cs+pet(d), y+11*cs+pet(d))
  ctx.lineTo(x+12*cs+pet(d), y+13*cs+pet(d))
  ctx.lineTo(x+10*cs+pet(d), y+13*cs+pet(d))
  ctx.lineTo(x+8*cs+pet(d), y+11*cs+pet(d))
  ctx.lineTo(x+7*cs+pet(d), y+12*cs+pet(d))
  ctx.lineTo(x+3*cs+pet(d), y+13*cs+pet(d))
  ctx.lineTo(x+2*cs+pet(d), y+12*cs+pet(d))
  ctx.lineTo(x+2*cs+pet(d), y+11*cs+pet(d))
  ctx.lineTo(x+0*cs+pet(d/2), y+10*cs+pet(d/2))
  ctx.lineTo(x+0*cs+pet(d/2), y+6*cs+pet(d/2))
  ctx.shadowColor = "#666666"
  ctx.shadowBlur = W*0.1
  ctx.shadowOffsetY = W*0.03
  ctx.fillStyle = "#bebebe"
  ctx.fill()
  ctx.shadowBlur = 0
  ctx.shadowOffsetY = 0
  ctx.strokeStyle = "#828181"
  ctx.stroke()
  x+= cs/2
  cs /= 1.04

  ctx.beginPath()
  ctx.moveTo(x+2*cs+pet(d/2), y+11*cs+pet(d/2))
  ctx.lineTo(x+5*cs+pet(d/2), y+9*cs+pet(d/2))
  ctx.stroke()

  //4
  ctx.beginPath()
