function groyneAt (x,y,W,color) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = true
  let cs = W/24, d = 0, i = 0, maxi = 1
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  if (WAVEY) {
    d = cs/2, maxi = 13
    ctx.lineWidth = 1 + document.getElementById("featuresize").value/150
  }
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  for (; i < maxi; i++) { // WAVEY
    //1
    ctx.beginPath()
    ctx.moveTo(x+0*cs+pet(d/2), y+12*cs+pet(d/2))
    cpx = x+10*cs
    cpy = y+10*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+24*cs+pet(d/2), y+12*cs+pet(d/2))
    ctx.stroke()

    //2
    if (i % 3 === 0) {
      ctx.lineWidth /= 2
      ctx.setLineDash([cs/2,cs])
      ctx.beginPath()
      ctx.moveTo(x+0*cs+pet(d/2), y+11.5*cs+pet(d/2))
      cpx = x+10*cs
      cpy = y+9.5*cs
      ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+24*cs+pet(d/2), y+11.5*cs+pet(d/2))
      ctx.stroke()
      y -= cs/2
      ctx.beginPath()
      ctx.moveTo(x+0*cs+pet(d/2), y+11*cs+pet(d/2))
      cpx = x+10*cs
      cpy = y+9.5*cs
      ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+24*cs+pet(d/2), y+11*cs+pet(d/2))
      ctx.stroke()
      y += cs/2
      ctx.setLineDash([])
      ctx.lineWidth *= 2
    }

    //3
    ctx.beginPath()
    ctx.moveTo(x+0*cs+pet(d/2), y+5*cs+pet(d/2))
    ctx.lineTo(x+24*cs+pet(d/2), y+5*cs+pet(d/2))
    ctx.stroke()

    //4
    ctx.beginPath()
    ctx.moveTo(x+0*cs+pet(d/2), y+3*cs+pet(d/2))
    cpx = x+6*cs
    cpy = y+3*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+8*cs+pet(d), y+4*cs+pet(d))
    cpx = x+10*cs
    cpy = y+5*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+11*cs+pet(d), y+5*cs+pet(d))
    cpx = x+17*cs
    cpy = y+5*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+18*cs+pet(d), y+4*cs+pet(d))
    cpx = x+20*cs
    cpy = y+3*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+24*cs+pet(d/2), y+4*cs+pet(d/2))
    ctx.stroke()

  } //WAVEY
  i = 0
  for (; i < 9; i++) {
    if (i === 0)
      x -= cs
    if (i === 1)
      x+= cs
    postAt(x+4*cs+pet(d/2), y+15*cs+pet(d/2), cs*8/(i*0.6+1), color)
    y -= cs*0.8 + pet(d)
    x += cs*1.6 + pet(d)
  }
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

