    cpy = y+1*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+19*cs+pet(d), y+1*cs+pet(d))
    cpx = x+19*cs
    cpy = y+8*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+14*cs+pet(d), y+11*cs+pet(d))
