function fly_abstractAt (x,y,W,color) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  let cs = W/24
  let p = [], cp = [], lastp = [], d = cs/2
  let cx = x+20*cs+pet(d), cy = y+12*cs+pet(d), angle = pet(180)

  //1
  let i = 0
  for (; i < 2; i++) {
    ctx.beginPath()
    p = rotatePoint(x+12*cs+pet(d), y+18*cs+pet(d) ,cx,cy,angle)
    ctx.moveTo(p[0],p[1])
    cpx = x+24*cs+pet(d)
    cpy = y+16*cs+pet(d)
    cp = rotatePoint(cpx,cpy,cx,cy,angle)
    p = rotatePoint(x+24*cs+pet(d), y+12*cs+pet(d),cx,cy,angle)
    ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
    cpx = x+24*cs+pet(d)
    cpy = y+8*cs+pet(d)
    cp = rotatePoint(cpx,cpy,cx,cy,angle)
    p = rotatePoint(x+12*cs+pet(d), y+6*cs+pet(d),cx,cy,angle)
    ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
    cpx = x+0*cs+pet(d)
    cpy = y+5*cs+pet(d)
    cp = rotatePoint(cpx,cpy,cx,cy,angle)
    p = rotatePoint(x+0*cs+pet(d), y+12*cs+pet(d),cx,cy,angle)
    ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
    cpx = x+0*cs+pet(d)
    cpy = y+19*cs+pet(d)
    cp = rotatePoint(cpx,cpy,cx,cy,angle)
    p = rotatePoint(x+12*cs+pet(d), y+18*cs+pet(d),cx,cy,angle)
    ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
    ctx.stroke()

    angle += 45 + pet(19)
    ctx.beginPath()
    p = rotatePoint(x+12*cs+pet(d), y+18*cs+pet(d) ,cx,cy,angle)
    ctx.moveTo(p[0],p[1])
    cpx = x+24*cs+pet(d)
    cpy = y+16*cs+pet(d)
    cp = rotatePoint(cpx,cpy,cx,cy,angle)
    p = rotatePoint(x+24*cs+pet(d), y+12*cs+pet(d),cx,cy,angle)
    ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
    cpx = x+24*cs+pet(d)
    cpy = y+8*cs+pet(d)
    cp = rotatePoint(cpx,cpy,cx,cy,angle)
    p = rotatePoint(x+12*cs+pet(d), y+6*cs+pet(d),cx,cy,angle)
    ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
    cpx = x+0*cs+pet(d)
    cpy = y+5*cs+pet(d)
    cp = rotatePoint(cpx,cpy,cx,cy,angle)
    p = rotatePoint(x+0*cs+pet(d), y+12*cs+pet(d),cx,cy,angle)
    ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
    cpx = x+0*cs+pet(d)
    cpy = y+19*cs+pet(d)
    cp = rotatePoint(cpx,cpy,cx,cy,angle)
    p = rotatePoint(x+12*cs+pet(d), y+18*cs+pet(d),cx,cy,angle)
    ctx.quadraticCurveTo(cp[0],cp[1],p[0],p[1])
    ctx.stroke()
    angle -= 45
  }
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

function Last_night_com_I_had_that_dream_againAt (x,y,W,color) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = true
  let cs = W/24, d = 0, i = 0, maxi = 1
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  if (WAVEY) {
    d = cs/2, maxi = 7
    ctx.lineWidth = 1 + document.getElementById("featuresize").value/150
  }
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  let v = document.getElementById("featuresize").value
  
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/150
  i = 0
  for (; i < maxi; i++) { // WAVEY
    //1
    ctx.beginPath()
    ctx.moveTo(x+6*cs+pet(d/2), y+20*cs+pet(d/2))
    ctx.lineTo(x+6*cs+pet(d), y+6*cs+pet(d))
    cpx = x+6*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+12*cs+pet(d), y+0*cs+pet(d))
    cpx = x+18*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+18*cs+pet(d), y+6*cs+pet(d))
    cpx = x+18*cs
    cpy = y+20*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+18*cs+pet(d/2), y+20*cs+pet(d/2))
    ctx.stroke()

    //2
    ctx.beginPath()
    ctx.moveTo(x+6*cs+pet(d/2), y+14*cs+pet(d/2))
    cpx = x+7*cs
    cpy = y+14*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+7*cs+pet(d), y+8*cs+pet(d))
    cpx = x+7*cs
    cpy = y+2*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+7*cs+pet(d), y+2*cs+pet(d))
    cpx = x+12*cs
    cpy = y+3*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+17*cs+pet(d), y+2*cs+pet(d))
    cpx = x+17*cs
    cpy = y+8*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+17*cs+pet(d), y+8*cs+pet(d))
    cpx = x+17*cs
    cpy = y+14*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+18*cs+pet(d/2), y+14*cs+pet(d/2))
    ctx.stroke()

    //3
    ctx.beginPath()
    ctx.moveTo(x+9*cs+pet(d/2), y+16*cs+pet(d/2))
    ctx.lineTo(x+11*cs+pet(d/2), y+16*cs+pet(d/2))
    ctx.stroke()

    //4
    ctx.beginPath()
    ctx.moveTo(x+13*cs+pet(d/2), y+16*cs+pet(d/2))
    ctx.lineTo(x+15*cs+pet(d/2), y+16*cs+pet(d/2))
    ctx.stroke()

    //5
    ctx.beginPath()
    ctx.moveTo(x+12*cs+pet(d/2), y+16*cs+pet(d/2))
    cpx = x+12*cs
    cpy = y+18*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+14*cs+pet(d), y+18*cs+pet(d))
    cpx = x+13*cs
    cpy = y+19*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+12*cs+pet(d/2), y+19*cs+pet(d/2))
    ctx.stroke()

    //6
    ctx.beginPath()
    ctx.moveTo(x+11*cs+pet(d/2), y+21*cs+pet(d/2))
    ctx.lineTo(x+13*cs+pet(d/2), y+21*cs+pet(d/2))
    ctx.stroke()

    //7
    ctx.beginPath()
    ctx.moveTo(x+6*cs+pet(d/2), y+15*cs+pet(d/2))
    cpx = x+5*cs
    cpy = y+15*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+6*cs+pet(d/2), y+17*cs+pet(d/2))
    ctx.stroke()

    //8
    ctx.beginPath()
    ctx.moveTo(x+18*cs+pet(d/2), y+15*cs+pet(d/2))
    cpx = x+19*cs
    cpy = y+15*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+18*cs+pet(d/2), y+17*cs+pet(d/2))
    ctx.stroke()

  } //WAVEY
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
  document.getElementById("featuresize").value = v/2
  let copy = shuffle(copyOf(atList))
  let filtered = []
  i = 0
  for (; i < copy.length; i++) {
    if (!(noDraw.includes(copy[i]) || autoDraw.includes(copy[i]) || tall.includes(copy[i])))
      filtered.push(copy[i])
  }
  window [randomPick(filtered)] (x+7.5*cs+pet(d/2), y+4*cs+pet(d/2), cs*9, color)
  document.getElementById("featuresize").value = v

  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

