function pattern (len,angle,curve,density,d,W,color,path) { // move to maincode
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let  H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = false
  let cs = W/24, i = 0, maxi = 1, xoff = 0
  let x = 0, y = 0, x0 = x, y0 = y, inc = 0//Math.PI/36
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/10
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "butt"
  if (!path) {
    path = new Path2D()
    path.moveTo(x,y)
    path.lineTo(x+W,y)
    path.lineTo(x+W,y+H)
    path.lineTo(x,y+H)
    path.lineTo(x,y)
  }
 // angle += 180
  angle *= Math.PI/180 // radians
  len *= cs/4
  curve *= (cs/3)
  d *= cs/3
  x -= len/2, y -= len/2
  let off = W/density, N = density*density *1.5
  for (; i < N; i++) {
    //if (ctx.isPointInPath(path, x, y, "evenodd")) {
      ctx.beginPath()
      ctx.moveTo(x+pet(d),y+pet(d))
      x2 = (len) * Math.cos(angle)+x
      y2 = (len) * Math.sin(angle)+y
      cpx = (curve) * Math.cos((angle+Math.PI/2))+(x+x2)/2 // cp at 90 deg
      cpy = (curve) * Math.sin((angle+Math.PI/2))+(y+y2)/2
      ctx.quadraticCurveTo(cpx, cpy, x2, y2) 
      //ctx.strokeStyle = randomPick(getCurrentPalette())
    //  ctx.lineWidth += pet(4)
      ctx.stroke()
   // }
    x += off
    angle += inc
    if (x >= x0+W) {
      x = x0 - len/2
      xoff = (xoff === 0)? len/2: 0;
      //x -= xoff
      y += off
    }
  }
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

function bogeymanAt (x,y,W,color) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = false
  let cs = W/24, d = 0, i = 0, maxi = 1
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "round"
  ctx.lineJoin = "round"
  y += cs*4
  // x+12*cs+pet(d/2), y+8*cs+pet(d/2)
  let hingeX = 12 + pet(8)
  let hingeY = 5 + pet(8)
  ctx.lineWidth = cs*4
  d = cs*9
  // body
  ctx.beginPath()
  ctx.moveTo(x+12*cs, y+21*cs)
  cpx = x+12*cs
  cpy = y+14*cs
  ctx.quadraticCurveTo(cpx+pet(d*1.5), cpy+pet(d*1.5), x+hingeX*cs, y+7*cs)
  cpx = x+12*cs
  cpy = y+4*cs
  ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+12*cs+pet(d*1.5), y+1*cs+pet(d*2))
  ctx.stroke()
  ctx.lineWidth = cs*1.5
  // arms
  ctx.beginPath()
  ctx.moveTo(x+4*cs+pet(d/2), y+10*cs+pet(d*2))
  cpx = x+8*cs
  cpy = y+7*cs
  ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+hingeX*cs, y+7*cs)
  cpx = x+16*cs
  cpy = y+7*cs
  ctx.quadraticCurveTo(cpx+pet(d*0.7), cpy+pet(d*0.7), x+20*cs+pet(d/2), y+4*cs+pet(d))
  ctx.stroke()

  ctx.lineWidth = 1
  d = 0

  ctx.beginPath()
  ctx.moveTo(x+8*cs+pet(d/2), y+21*cs+pet(d/2))
  ctx.lineTo(x+16*cs+pet(d), y+21*cs+pet(d))
  ctx.lineTo(x+16*cs+pet(d), y+24*cs+pet(d))
  ctx.lineTo(x+8*cs+pet(d/2), y+24*cs+pet(d/2))
  ctx.fillStyle = savedF
  ctx.fill()

  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  ctx.beginPath()
  ctx.moveTo(x+8*cs+pet(d/2), y+23*cs+pet(d/2))
  cpx = x+12*cs
  cpy = y+24*cs
  ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+16*cs+pet(d), y+23*cs+pet(d))
  cpx = x+16*cs
  cpy = y+21*cs
  ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+16*cs+pet(d), y+21*cs+pet(d))
  cpx = x+16*cs
  cpy = y+20*cs
  ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+12*cs+pet(d), y+20*cs+pet(d))
  cpx = x+8*cs
  cpy = y+20*cs
  ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+8*cs+pet(d), y+21*cs+pet(d))
  cpx = x+8*cs
  cpy = y+23*cs
  ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+8*cs+pet(d/2), y+23*cs+pet(d/2))
  ctx.stroke()

  //4
  ctx.beginPath()
  ctx.moveTo(x+8*cs+pet(d/2), y+21*cs+pet(d/2))
  cpx = x+12*cs
  cpy = y+22*cs
  ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+16*cs+pet(d/2), y+21*cs+pet(d/2))
  ctx.stroke()

  ctx.fillStyle = color
  let fs = W*0.05
  ctx.font = "800 "+(fs)+"pt Garamond"
  ctx.fillText("S", x+8.7*cs, y+22.8*cs+pet(d/2))
  ctx.fillText("A", x+8.7*cs+fs*1.3, y+23.*cs+pet(d/2))
  ctx.fillText("L", x+8.7*cs+fs*3, y+23*cs+pet(d/2))
  ctx.fillText("E", x+8.7*cs+fs*4.3, y+22.8*cs+pet(d/2))
  ctx.fillText("!", x+8.7*cs+fs*5.4, y+22.5*cs+pet(d/2))
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}
