function puzzledAt (x,y,W,color) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = false
  let cs = W/24, d = 0, i = 0, maxi = 1
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/30
  if (WAVEY) {
    d = cs/2, maxi = 13
    ctx.lineWidth = 1 + document.getElementById("featuresize").value/150
  }
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  y -= cs*2
  for (; i < maxi; i++) { // WAVEY
    //1
    ctx.beginPath()
    ctx.moveTo(x+10*cs+pet(d/2), y+2*cs+pet(d/2))
    cpx = x+10*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+11*cs+pet(d), y+0*cs+pet(d))
    cpx = x+12*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+12*cs+pet(d), y+2*cs+pet(d))
    ctx.lineTo(x+22*cs+pet(d), y+2*cs+pet(d))
    ctx.lineTo(x+23*cs+pet(d), y+3*cs+pet(d))
    ctx.lineTo(x+23*cs+pet(d), y+25*cs+pet(d))
    ctx.lineTo(x+1*cs+pet(d), y+25*cs+pet(d))
    ctx.lineTo(x+0*cs+pet(d), y+24*cs+pet(d))
    ctx.lineTo(x+0*cs+pet(d), y+2*cs+pet(d))
    ctx.lineTo(x+10*cs+pet(d/2), y+2*cs+pet(d/2))
    ctx.stroke()
    ctx.beginPath()
    ctx.moveTo(x+13*cs+pet(d/2), y+2*cs+pet(d/2))
    cpx = x+13*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+12*cs+pet(d), y+0*cs+pet(d))
    ctx.lineTo(x+11*cs+pet(d/2), y+0*cs+pet(d/2))
    ctx.stroke()
    //2
    ctx.beginPath()
    ctx.moveTo(x+0*cs+pet(d/2), y+24*cs+pet(d/2))
    ctx.lineTo(x+22*cs+pet(d), y+24*cs+pet(d))
    ctx.lineTo(x+22*cs+pet(d/2), y+2*cs+pet(d/2))
    ctx.stroke()

    //3
    ctx.beginPath()
    ctx.moveTo(x+22*cs+pet(d/2), y+24*cs+pet(d/2))
    ctx.lineTo(x+23*cs+pet(d/2), y+25*cs+pet(d/2))
    ctx.stroke()

    //5
    ctx.beginPath()
    ctx.arc(x+11*cs+pet(d/2), y+1.3*cs+pet(d/2), cs/3.5, 0, 2*Math.PI) // arc
    ctx.stroke()

    ctx.save()
    //4
    ctx.beginPath()
    ctx.moveTo(x+1*cs+pet(d/2), y+3*cs+pet(d/2))
    ctx.lineTo(x+21*cs+pet(d), y+3*cs+pet(d))
    ctx.lineTo(x+21*cs+pet(d), y+23*cs+pet(d))
    ctx.lineTo(x+1*cs+pet(d), y+23*cs+pet(d))
    ctx.lineTo(x+1*cs+pet(d/2), y+3*cs+pet(d/2))
    ctx.globalAlpha = 0.33
    ctx.fill()
    ctx.globalAlpha = 1
    ctx.stroke()
    ctx.clip()

  } //WAVEY
  i = 0
  let nums = shuffle([1,2,3,4,5,6,7,8]), idx = 0
  ctx.font = "italic " +(cs*4)+"pt Garamond"
  let space = Math.floor(Math.random()*9)
  let w = cs*20/3, xoff = 0, yoff = 0, x0 = x, y0 = y
  for (; i < 9; i++) {
    if (i !== space) {
      atileAt(x+cs*1, y+cs*3, w, color, savedF)
      ctx.fillStyle = color
      ctx.strokeText(nums[idx++], x+cs*2.75, y+cs*8)
    }
    x += w
    if (x >= x0+W*0.8) {
      x = x0
      y += w
    }
  }
  ctx.restore()
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

function atileAt (x,y,W,color,fill) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = false
  let cs = W/24, d = 0, i = 0, maxi = 1
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  if (WAVEY) {
    d = cs/2, maxi = 1
    1 + document.getElementById("featuresize").value/150
  }
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  for (; i < maxi; i++) { // WAVEY
    //1
    ctx.beginPath()
    ctx.moveTo(x+0*cs+pet(d/2), y+2*cs+pet(d/2))
    cpx = x+0*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+2*cs+pet(d), y+0*cs+pet(d))
    cpx = x+22*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+22*cs+pet(d), y+0*cs+pet(d))
    cpx = x+24*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+24*cs+pet(d), y+2*cs+pet(d))
    cpx = x+24*cs
    cpy = y+22*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+24*cs+pet(d), y+22*cs+pet(d))
    cpx = x+24*cs
    cpy = y+25*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+22*cs+pet(d), y+25*cs+pet(d))
    cpx = x+2*cs
    cpy = y+25*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+2*cs+pet(d), y+25*cs+pet(d))
    cpx = x+0*cs
    cpy = y+24*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+0*cs+pet(d), y+22*cs+pet(d))
    cpx = x+0*cs
    cpy = y+2*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+0*cs+pet(d/2), y+2*cs+pet(d/2))
    ctx.fillStyle = fill
    ctx.fill()
    ctx.stroke()

    //1 tabs
    x += 2*cs
    ctx.beginPath()
    ctx.moveTo(x+22*cs+pet(d/2), y+4*cs+pet(d/2))
    cpx = x+24*cs
    cpy = y+4*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+24*cs+pet(d), y+6*cs+pet(d))
    cpx = x+24*cs
    cpy = y+18*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+24*cs+pet(d), y+18*cs+pet(d))
    cpx = x+24*cs
    cpy = y+20*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+22*cs+pet(d/2), y+20*cs+pet(d/2))
    ctx.fill()
    ctx.stroke()
    x -= 2*cs
    y += 2*cs
    //2
    ctx.beginPath()
    ctx.moveTo(x+4*cs+pet(d/2), y+22*cs+pet(d/2))
    cpx = x+4*cs
    cpy = y+24*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+6*cs+pet(d), y+24*cs+pet(d))
    cpx = x+18*cs
    cpy = y+24*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+18*cs+pet(d), y+24*cs+pet(d))
    cpx = x+20*cs
    cpy = y+24*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+20*cs+pet(d/2), y+22*cs+pet(d/2))
    ctx.fill()
    ctx.stroke()
    y -= 2*cs
    //1
    ctx.beginPath()
    ctx.moveTo(x+0*cs+pet(d/2), y+21*cs+pet(d/2))
    cpx = x+0*cs
    cpy = y+23*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+2*cs+pet(d), y+23*cs+pet(d))
    cpx = x+21*cs
    cpy = y+23*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+21*cs+pet(d), y+23*cs+pet(d))
    cpx = x+23*cs
    cpy = y+23*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+23*cs+pet(d), y+21*cs+pet(d))
    cpx = x+23*cs
    cpy = y+2*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+23*cs+pet(d), y+2*cs+pet(d))
    cpx = x+23*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+21*cs+pet(d/2), y+0*cs+pet(d/2))
    ctx.stroke()

  } //WAVEY
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}

function trackingAt (x,y,W,color, fill) {
  let canvas = document.getElementById("myCanvas")
  let ctx = canvas.getContext("2d")
  let H = W, cpx, cpy, points = []
  let savedF = ctx.fillStyle, savedS = ctx.strokeStyle, WAVEY = true
  let cs = W/24, d = 0, i = 0, maxi = 1
  ctx.lineWidth = 1 + document.getElementById("featuresize").value/50
  if (WAVEY) {
    d = cs/2, maxi = 13
    ctx.lineWidth = 1 + document.getElementById("featuresize").value/150
  }
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineCap = "square"
  ctx.lineJoin = "bevel"
  for (; i < maxi; i++) { // WAVEY
    ctx.beginPath()
    ctx.moveTo(x+12*cs+pet(d/2), y+26*cs+pet(d/2))
    cpx = x+20*cs
    cpy = y+14*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+20*cs+pet(d), y+8*cs+pet(d))
    cpx = x+20*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+12*cs+pet(d), y+0*cs+pet(d))
    cpx = x+4*cs
    cpy = y+0*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+4*cs+pet(d), y+8*cs+pet(d))
    cpx = x+4*cs
    cpy = y+14*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+12*cs+pet(d/2), y+26*cs+pet(d/2))
    ctx.stroke()

    //2
    ctx.beginPath()
    ctx.moveTo(x+5*cs+pet(d/2), y+8*cs+pet(d/2))
    cpx = x+12*cs
    cpy = y+3*cs
    ctx.quadraticCurveTo(cpx+pet(d), cpy+pet(d), x+19*cs+pet(d), y+8*cs+pet(d))
    cpx = x+12*cs
    cpy = y+13*cs
    ctx.quadraticCurveTo(cpx+pet(d/2), cpy+pet(d/2), x+5*cs+pet(d/2), y+8*cs+pet(d/2))
    ctx.fillStyle = fill
    ctx.stroke()

    //3
    ctx.beginPath()
    ctx.arc(x+12*cs+pet(d/2), y+8*cs+pet(d/2),cs*2.5, 0, 2*Math.PI)
    ctx.stroke()

    ctx.beginPath()
    ctx.arc(x+12*cs+pet(d/2), y+8*cs+pet(d/2),cs*1.6, 0, 2*Math.PI)
    ctx.stroke()

  } //WAVEY
  ctx.save()
  let cx = x+12*cs+pet(d/2), cy = y+8*cs+pet(d/2), x0 = x, y0 = y
  let angle = 0, r = W, inc = Math.PI/10
  i = 0
  ctx.lineCap = "butt"
  ctx.lineWidth *= 3
  ctx.setLineDash([cs/4, cs*1.2])
  ctx.beginPath()
  ctx.moveTo(x-cs*4, y - cs*8)
  ctx.lineTo(x+W+cs*4, y - cs*8)
  ctx.lineTo(x+W+cs*4, y +H+ cs*7)
  ctx.lineTo(x-cs*4, y +H+ cs*7)
  ctx.closePath()
  ctx.clip()
  for (;i < 20; i++) {
    x = r * Math.cos(angle)+cx
    y = r * Math.sin(angle)+cy  
    ctx.beginPath()
    ctx.moveTo(cx,cy)
    ctx.lineTo(x,y)
    ctx.stroke()
    angle += inc
  }
  ctx.setLineDash([])
  ctx.restore()
  ctx.strokeStyle = savedS
  ctx.fillStyle = savedF
}
